import React, { useEffect, useState, useCallback } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";

export default function ProductosPorCategoria() {
  const { id } = useParams(); // id de la categoría
  const [productos, setProductos] = useState([]);
  const [categoria, setCategoria] = useState(null);
  const [loading, setLoading] = useState(true);

  // Obtener productos
  const obtenerProductos = useCallback(async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");

      // 🔴 AQUÍ ESTABA EL ERROR
      const filtrados = res.data.filter(
        (p) => Number(p.CategoriaID) === Number(id)
      );

      setProductos(filtrados);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  // Obtener nombre de la categoría
  const obtenerCategoria = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/categorias/${id}`
      );
      setCategoria(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categoría:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
    obtenerCategoria();
  }, [obtenerProductos]);

  if (loading) {
    return <p className="text-center mt-5">Cargando productos...</p>;
  }

  return (
    <div className="container mt-5">
      <h2 className="mb-4 text-center">
        Productos de la categoría:{" "}
        <span className="text-primary">
          {categoria?.Nombre || "Sin nombre"}
        </span>
      </h2>

      {productos.length === 0 ? (
        <p className="text-center text-muted">
          No hay productos en esta categoría.
        </p>
      ) : (
        <div className="row">
          {productos.map((p) => (
            <div key={p.ProductoID} className="col-md-4 mb-4">
              <div className="card h-100 shadow-sm">
                {p.Imagen && (
                  <img
                    src={`http://localhost:5000/uploads/${p.Imagen}`}
                    className="card-img-top"
                    alt={p.Nombre}
                    style={{ height: "200px", objectFit: "cover" }}
                  />
                )}
                <div className="card-body text-center">
                  <h5 className="card-title">{p.Nombre}</h5>
                  <p className="card-text">{p.Descripcion}</p>
                  <p className="fw-bold">${p.Precio}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
